class Solution(object):
    def minEnd(self, n, x):
        result = x
        m = n - 1
        bit_m = 0
        bit_r = 0
        while (m >> bit_m) > 0:
            # Skip set bits in x
            while (x >> bit_r) & 1:
                bit_r += 1
            if (m >> bit_m) & 1:
                result |= (1 << bit_r)
            bit_m += 1
            bit_r += 1
        return result
